import scala.io.Source
import scala.xml._

case class Setting(key: String, value: String)

object ConfigService {
  val apiEndpoint = "http://your-api-endpoint" // replace with your actual API endpoint

  def loadSettings(xmlStr: String): Seq[Setting] = {
    val xmlDoc = XML.loadString(xmlStr)
    (xmlDoc \\ "setting").map { settingNode =>
      Setting(
        (settingNode \ "@key").text,
        (settingNode \ "@value").text
      )
    }
  }

  def getSettingsFromApi(): Seq[Setting] = {
    val response = Source.fromURL(apiEndpoint).mkString
    loadSettings(response)
  }
}